definitions.inputs:
={{ ((parameter) => { function getInputs(parameters) {
    const chunkingMode = parameters?.chunkingMode;
    const operationMode = parameters?.operationMode;
    const inputs = [
        { displayName: '', type: 'main' },
        {
            displayName: 'Model',
            maxConnections: 1,
            type: 'ai_languageModel',
            required: true,
        },
    ];
    if (operationMode === 'documentLoader') {
        inputs.push({
            displayName: 'Document',
            type: 'ai_document',
            required: true,
            maxConnections: 1,
        });
        return inputs;
    }
    if (chunkingMode === 'advanced') {
        inputs.push({
            displayName: 'Text Splitter',
            type: 'ai_textSplitter',
            required: false,
            maxConnections: 1,
        });
        return inputs;
    }
    return inputs;
}; return getInputs(parameter) })($parameter) }}
